CREATE OR REPLACE FUNCTION public.updateonrampbystatusandcurrency(p_action integer, p_status character varying, p_currency character varying)
 RETURNS jsonb[]
 LANGUAGE plpgsql
AS $function$
DECLARE 
    c_paymentPending jsonb;
    c_result jsonb[] := '{}';
BEGIN
    FOR c_paymentPending IN 
        SELECT jsonb_build_object(
            'id', or2.id,
            'txHash', or2."txHash",
            'address', or2."depositAddress",
            'toAmount', q."toAmount",
            'chain', q."chain",
            'contador', or2."totalSend"
        )
	    FROM 
	       on_ramps or2 
	    INNER JOIN 
	        "quote" q ON or2."quote" = q.id
	    WHERE 
	        or2."fiatPaymentInstructionsId" % 2 = p_action
			AND or2.status = p_status::on_ramps_status_enum
			AND q."fromCurrency"::varchar = p_currency::varchar
			and or2."txHash" is not null
			and or2."totalSend" = 1
	    ORDER BY 
	     	or2."fiatPaymentInstructionsId" ASC
	    LIMIT 500
    LOOP
        c_result := array_append(c_result, c_paymentPending);
    END LOOP;
   
    RETURN c_result;
END;
$function$;

CREATE OR REPLACE FUNCTION public.usuarios_por_status(status character varying, country character varying)
 RETURNS TABLE(count bigint, statu character varying)
 LANGUAGE plpgsql
AS $function$
BEGIN
    RETURN QUERY
    SELECT COUNT(*), ic."statusKyc"
    FROM individual_customers ic
    WHERE ic."statusKyc" = $1 AND ic.country = $2
    GROUP BY ic."statusKyc";
END; $function$;

